   200→// ZeroBucket returns the zero bucket. This method panics if the schema is for custom buckets.
   201→func (h *Histogram) ZeroBucket() Bucket[uint64] {
   202→	if h.UsesCustomBuckets() {
   203→		panic("histograms with custom buckets have no zero bucket")
   204→	}
   205→	return Bucket[uint64]{
   206→		Lower:          -h.ZeroThreshold,
   207→		Upper:          h.ZeroThreshold,
   208→		LowerInclusive: true,
   209→		UpperInclusive: true,
   210→		Count:          h.ZeroCount,
   211→	}
   212→}
   213→
   214→// PositiveBucketIterator returns a BucketIterator to iterate over all positive
   215→// buckets in ascending order (starting next to the zero bucket and going up).
   216→func (h *Histogram) PositiveBucketIterator() BucketIterator[uint64] {
   217→	it := newRegularBucketIterator(h.PositiveSpans, h.PositiveBuckets, h.Schema, true, h.CustomValues)
   218→	return &it
   219→}
   220→
   221→// NegativeBucketIterator returns a BucketIterator to iterate over all negative
   222→// buckets in descending order (starting next to the zero bucket and going down).
   223→func (h *Histogram) NegativeBucketIterator() BucketIterator[uint64] {
   224→	it := newRegularBucketIterator(h.NegativeSpans, h.NegativeBuckets, h.Schema, false, nil)
   225→	return &it
   226→}
   227→
   228→// CumulativeBucketIterator returns a BucketIterator to iterate over a
   229→// cumulative view of the buckets. This method currently only supports
   230→// Histograms without negative buckets and panics if the Histogram has negative
   231→// buckets. It is currently only used for testing.
   232→func (h *Histogram) CumulativeBucketIterator() BucketIterator[uint64] {
   233→	if len(h.NegativeBuckets) > 0 {
   234→		panic("CumulativeBucketIterator called on Histogram with negative buckets")
   235→	}
   236→	return &cumulativeBucketIterator{h: h, posSpansIdx: -1}
   237→}
   238→
   239→// Equals returns true if the given histogram matches exactly.
   240→// Exact match is when there are no new buckets (even empty) and no missing buckets,
   241→// and all the bucket values match. Spans can have different empty length spans in between,
   242→// but they must represent the same bucket layout to match.
   243→// Sum is compared based on its bit pattern because this method
   244→// is about data equality rather than mathematical equality.
   245→// We ignore fields that are not used based on the exponential / custom buckets schema,
   246→// but check fields where differences may cause unintended behaviour even if they are not
   247→// supposed to be used according to the schema.
   248→func (h *Histogram) Equals(h2 *Histogram) bool {
   249→	if h2 == nil {
   250→		return h == nil
   251→	}
   252→
   253→	if h.Schema != h2.Schema || h.Count != h2.Count ||
   254→		math.Float64bits(h.Sum) != math.Float64bits(h2.Sum) {
   255→		return false
   256→	}
   257→
   258→	if h.UsesCustomBuckets() {
   259→		if !CustomBucketBoundsMatch(h.CustomValues, h2.CustomValues) {
   260→			return false
   261→		}
   262→	}
   263→
   264→	if h.ZeroThreshold != h2.ZeroThreshold || h.ZeroCount != h2.ZeroCount {
   265→		return false
   266→	}
   267→
   268→	if !spansMatch(h.NegativeSpans, h2.NegativeSpans) {
   269→		return false
   270→	}
   271→	if !slices.Equal(h.NegativeBuckets, h2.NegativeBuckets) {
   272→		return false
   273→	}
   274→
   275→	if !spansMatch(h.PositiveSpans, h2.PositiveSpans) {
   276→		return false
   277→	}
   278→	if !slices.Equal(h.PositiveBuckets, h2.PositiveBuckets) {
   279→		return false
   280→	}
   281→
   282→	return true
   283→}
   284→
   285→// spansMatch returns true if both spans represent the same bucket layout
   286→// after combining zero length spans with the next non-zero length span.
   287→func spansMatch(s1, s2 []Span) bool {
   288→	if len(s1) == 0 && len(s2) == 0 {
   289→		return true
   290→	}
   291→
   292→	s1idx, s2idx := 0, 0
   293→	for {
   294→		if s1idx >= len(s1) {
   295→			return allEmptySpans(s2[s2idx:])
   296→		}
   297→		if s2idx >= len(s2) {
   298→			return allEmptySpans(s1[s1idx:])
   299→		}
   300→
   301→		currS1, currS2 := s1[s1idx], s2[s2idx]
   302→		s1idx++
   303→		s2idx++
   304→		if currS1.Length == 0 {
   305→			// This span is zero length, so we add consecutive such spans
   306→			// until we find a non-zero span.
   307→			for ; s1idx < len(s1) && s1[s1idx].Length == 0; s1idx++ {
   308→				currS1.Offset += s1[s1idx].Offset
   309→			}
   310→			if s1idx < len(s1) {
   311→				currS1.Offset += s1[s1idx].Offset
   312→				currS1.Length = s1[s1idx].Length
   313→				s1idx++
   314→			}
   315→		}
   316→		if currS2.Length == 0 {
   317→			// This span is zero length, so we add consecutive such spans
   318→			// until we find a non-zero span.
   319→			for ; s2idx < len(s2) && s2[s2idx].Length == 0; s2idx++ {
   320→				currS2.Offset += s2[s2idx].Offset
   321→			}
   322→			if s2idx < len(s2) {
   323→				currS2.Offset += s2[s2idx].Offset
   324→				currS2.Length = s2[s2idx].Length
   325→				s2idx++
   326→			}
   327→		}
   328→
   329→		if currS1.Length == 0 && currS2.Length == 0 {
   330→			// The last spans of both set are zero length. Previous spans match.
   331→			return true
   332→		}
   333→
   334→		if currS1.Offset != currS2.Offset || currS1.Length != currS2.Length {
   335→			return false
   336→		}
   337→	}
   338→}
   339→
   340→func allEmptySpans(s []Span) bool {
   341→	for _, ss := range s {
   342→		if ss.Length > 0 {
   343→			return false
   344→		}
   345→	}
   346→	return true
   347→}
   348→
   349→// Compact works like FloatHistogram.Compact. See there for detailed
   350→// explanations.
   351→func (h *Histogram) Compact(maxEmptyBuckets int) *Histogram {
   352→	h.PositiveBuckets, _, h.PositiveSpans = compactBuckets(
   353→		h.PositiveBuckets, nil, h.PositiveSpans, maxEmptyBuckets, true,
   354→	)
   355→	h.NegativeBuckets, _, h.NegativeSpans = compactBuckets(
   356→		h.NegativeBuckets, nil, h.NegativeSpans, maxEmptyBuckets, true,
   357→	)
   358→	return h
   359→}
   360→
   361→// ToFloat returns a FloatHistogram representation of the Histogram. It is a deep
   362→// copy (e.g. spans are not shared). The function accepts a FloatHistogram as an
   363→// argument whose memory will be reused and overwritten if provided. If this
   364→// argument is nil, a new FloatHistogram will be allocated.
   365→func (h *Histogram) ToFloat(fh *FloatHistogram) *FloatHistogram {
   366→	if fh == nil {
   367→		fh = &FloatHistogram{}
   368→	}
   369→	fh.CounterResetHint = h.CounterResetHint
   370→	fh.Schema = h.Schema
   371→	fh.Count = float64(h.Count)
   372→	fh.Sum = h.Sum
   373→
   374→	if h.UsesCustomBuckets() {
   375→		fh.ZeroThreshold = 0
   376→		fh.ZeroCount = 0
   377→		fh.NegativeSpans = clearIfNotNil(fh.NegativeSpans)
   378→		fh.NegativeBuckets = clearIfNotNil(fh.NegativeBuckets)
   379→		// Custom values are interned, it's ok to copy by reference.
   380→		fh.CustomValues = h.CustomValues
   381→	} else {
   382→		fh.ZeroThreshold = h.ZeroThreshold
   383→		fh.ZeroCount = float64(h.ZeroCount)
   384→
   385→		fh.NegativeSpans = resize(fh.NegativeSpans, len(h.NegativeSpans))
   386→		copy(fh.NegativeSpans, h.NegativeSpans)
   387→
   388→		fh.NegativeBuckets = resize(fh.NegativeBuckets, len(h.NegativeBuckets))
   389→		var currentNegative float64
   390→		for i, b := range h.NegativeBuckets {
   391→			currentNegative += float64(b)
   392→			fh.NegativeBuckets[i] = currentNegative
   393→		}
   394→		// Custom values are interned, no need to reset.
   395→		fh.CustomValues = nil
   396→	}
   397→
   398→	fh.PositiveSpans = resize(fh.PositiveSpans, len(h.PositiveSpans))
   399→	copy(fh.PositiveSpans, h.PositiveSpans)
   400→
   401→	fh.PositiveBuckets = resize(fh.PositiveBuckets, len(h.PositiveBuckets))
   402→	var currentPositive float64
   403→	for i, b := range h.PositiveBuckets {
   404→		currentPositive += float64(b)
   405→		fh.PositiveBuckets[i] = currentPositive
   406→	}
   407→
   408→	return fh
   409→}
   410→
   411→func resize[T any](items []T, n int) []T {
   412→	if cap(items) < n {
   413→		return make([]T, n)
   414→	}
   415→	return items[:n]
   416→}
   417→
   418→// Validate validates consistency between span and bucket slices. Also, buckets are checked
   419→// against negative values. We check to make sure there are no unexpected fields or field values
   420→// based on the exponential / custom buckets schema.
   421→// For histograms that have not observed any NaN values (based on IsNaN(h.Sum) check), a
   422→// strict h.Count = nCount + pCount + h.ZeroCount check is performed.
   423→// Otherwise, only a lower bound check will be done (h.Count >= nCount + pCount + h.ZeroCount),
   424→// because NaN observations do not increment the values of buckets (but they do increment
   425→// the total h.Count).
   426→func (h *Histogram) Validate() error {
   427→	var nCount, pCount uint64
   428→	switch {
   429→	case IsCustomBucketsSchema(h.Schema):
   430→		if err := checkHistogramCustomBounds(h.CustomValues, h.PositiveSpans, len(h.PositiveBuckets)); err != nil {
   431→			return fmt.Errorf("custom buckets: %w", err)
   432→		}
   433→		if h.ZeroCount != 0 {
   434→			return ErrHistogramCustomBucketsZeroCount
   435→		}
   436→		if h.ZeroThreshold != 0 {
   437→			return ErrHistogramCustomBucketsZeroThresh
   438→		}
   439→		if len(h.NegativeSpans) > 0 {
   440→			return ErrHistogramCustomBucketsNegSpans
   441→		}
   442→		if len(h.NegativeBuckets) > 0 {
   443→			return ErrHistogramCustomBucketsNegBuckets
   444→		}
   445→	case IsExponentialSchema(h.Schema):
   446→		if err := checkHistogramSpans(h.PositiveSpans, len(h.PositiveBuckets)); err != nil {
   447→			return fmt.Errorf("positive side: %w", err)
   448→		}
   449→		if err := checkHistogramSpans(h.NegativeSpans, len(h.NegativeBuckets)); err != nil {
   450→			return fmt.Errorf("negative side: %w", err)
   451→		}
   452→		err := checkHistogramBuckets(h.NegativeBuckets, &nCount, true)
   453→		if err != nil {
   454→			return fmt.Errorf("negative side: %w", err)
   455→		}
   456→		if h.CustomValues != nil {
   457→			return ErrHistogramExpSchemaCustomBounds
   458→		}
   459→	default:
   460→		return InvalidSchemaError(h.Schema)
   461→	}
   462→	err := checkHistogramBuckets(h.PositiveBuckets, &pCount, true)
   463→	if err != nil {
   464→		return fmt.Errorf("positive side: %w", err)
   465→	}
   466→
   467→	sumOfBuckets := nCount + pCount + h.ZeroCount
   468→	if math.IsNaN(h.Sum) {
   469→		if sumOfBuckets > h.Count {
   470→			return fmt.Errorf("%d observations found in buckets, but the Count field is %d: %w", sumOfBuckets, h.Count, ErrHistogramCountNotBigEnough)
   471→		}
   472→	} else {
   473→		if sumOfBuckets != h.Count {
   474→			return fmt.Errorf("%d observations found in buckets, but the Count field is %d: %w", sumOfBuckets, h.Count, ErrHistogramCountMismatch)
   475→		}
   476→	}
   477→
   478→	return nil
   479→}
