    atomicAddFloat(&hc.sumBits, v)
    if doSparse && !math.IsNaN(v) {
        frac, exp := math.Frexp(math.Abs(v))
        if schema > 0 {
            // High-resolution: binary search in nativeHistogramBounds table
            key = sort.SearchFloat64s(bounds, frac) + (exp-1)*len(bounds)
        } else {
            // Low-resolution: use exponent directly with offset
            key = exp
            if frac == 0.5 { key-- }
            offset := (1 << -schema) - 1
            key = (key + offset) >> -schema
        }
        // Route to positive, negative, or zero bucket
        switch {
        case v > zeroThreshold:
            bucketCreated = addToBucket(&hc.nativeHistogramBucketsPositive, key, 1)
        case v < -zeroThreshold:
            bucketCreated = addToBucket(&hc.nativeHistogramBucketsNegative, key, 1)
        default:
            atomic.AddUint64(&hc.nativeHistogramZeroBucket, 1)
        }
        if bucketCreated {
            atomic.AddUint32(&hc.nativeHistogramBucketsNumber, 1)
        }
    }
    atomic.AddUint64(&hc.count, 1)  // count is always incremented last
}
```

#### Native Sparse Bucket Storage

```go
// addToBucket increments a sparse bucket by increment; returns true if a new bucket was created.
func addToBucket(buckets *sync.Map, key int, increment int64) bool {
    if existingBucket, ok := buckets.Load(key); ok {
        atomic.AddInt64(existingBucket.(*int64), increment)
        return false
    }
    // Slow path: allocate new bucket, handling concurrent creation race
    newBucket := increment
    if actualBucket, loaded := buckets.LoadOrStore(key, &newBucket); loaded {
        atomic.AddInt64(actualBucket.(*int64), increment)
        return false
    }
    return true
}
```

Sparse (native) buckets use a `sync.Map` keyed by integer bucket index. The bucket key for `schema > 0` is computed as `sort.SearchFloat64s(bounds, frac) + (exp-1)*len(bounds)`, where `bounds` is the pre-computed `nativeHistogramBounds[schema]` slice. For `schema <= 0`, the key is derived directly from the binary exponent of the observed value, bit-shifted by `-schema`.

#### Serialization to Spans/Deltas — `makeBuckets()`

```go
func makeBuckets(buckets *sync.Map) ([]*dto.BucketSpan, []int64) {
    // Collect and sort all active bucket indices.
    // Small gaps (<= 2) are filled in-line; larger gaps start a new Span.
    appendDelta := func(count int64) {
        *spans[len(spans)-1].Length++
        deltas = append(deltas, count-prevCount)  // encode as delta from previous
        prevCount = count
    }
    // ...
}
```

This converts the in-memory `sync.Map` (absolute counts per key) into the wire format used by `Histogram.PositiveBuckets`: a list of `BucketSpan` descriptors plus a **delta-encoded** `[]int64` of counts.

#### Count Validation — `validateCount()`

```go
func validateCount(sum float64, count uint64, negativeBuckets, positiveBuckets map[int]int64, zeroBucket uint64) error {
    var bucketPopulationSum int64
    for _, v := range positiveBuckets { bucketPopulationSum += v }
    for _, v := range negativeBuckets { bucketPopulationSum += v }
    bucketPopulationSum += int64(zeroBucket)

    if math.IsNaN(sum) && bucketPopulationSum > int64(count) ||
        !math.IsNaN(sum) && bucketPopulationSum != int64(count) {
        return errors.New("the sum of all bucket populations exceeds the count of observations")
    }
    return nil
}
```

#### PromQL `histogram_count` Function

```go
// functions.go, line 1599
